 4	
 5	import { useUrlFilters } from '../useUrlFilters';
 6	
 7	afterEach(cleanup);
 8	beforeEach(() => {
 9	  Object.defineProperty(window, 'location', {
10	    value: { assign: jest.fn() },
11	    writable: true,
12	  });
13	  window.location.pathname = '';
14	  window.history.pushState = jest.fn();
15	});
16	
17	describe('parse filters from the URL on initialization', () => {
18	  const cases: [string, string, string[] | undefined][] = [
19	    ['gets initialized with single value', '?name=%5B"foo"%5D', ['foo']],
20	    ['gets initialized with 2 values', '?name=%5B"foo"%2C"bar"%5D', ['foo', 'bar']],
21	    ['ignores empty JSON array', '?name=%5B%5D', undefined],
22	    ['ignores data different then JSON array', '?name="foo"', undefined],
23	    ['ignores corrupted data', '?name=%5B%foo', undefined],
24	  ];
25	
26	  cases.forEach(([description, search, output]) => {
27	    it(description, () => {
28	      window.location.search = search;
29	      const {
30	        result: {
31	          current: [selectedFilters],
32	        },
33	      } = renderHook(() =>
34	        useUrlFilters({
35	          fields: [{ label: NAME, resourceFieldId: NAME }],
36	        }),
37	      );
38	      expect(selectedFilters[NAME]).toStrictEqual(output);
39	    });
40	  });
41	
42	  it('ignores unknown field', () => {
43	    window.location.search = '?ready=%5B"True"%5D';
44	    const {
45	      result: {
46	        current: [selectedFilters],
47	      },
48	    } = renderHook(() =>
49	      useUrlFilters({
50	        fields: [{ label: NAME, resourceFieldId: NAME }],
51	      }),
52	    );
53	    expect(Object.entries(selectedFilters).length).toStrictEqual(0);
54	  });
55	});
56	
57	describe('display currently selected filters in the URL', () => {
58	  test.each([
59	    {
60	      description: 'displays single value',
61	      initialUrl: '?foo=bar',
62	      update: ['foo'],
63	      pushedState: '?foo=bar&name=%5B%22foo%22%5D',
64	    },
65	    {
66	      description: 'updates a value',
67	      initialUrl: '?foo=bar&name=%5B"foo"%5D',
68	      update: ['bar'],
69	      pushedState: '?foo=bar&name=%5B%22bar%22%5D',
70	    },
71	    {
72	      description: 'removes a filter',
73	      initialUrl: '?foo=bar&name=%5B"foo"%5D',
74	      update: [],
75	      pushedState: '?foo=bar',
76	    },
77	  ])('%s', ({ description, initialUrl, update, pushedState }) => {
78	    window.location.search = initialUrl;
79	    const {
80	      result: {
81	        current: [, setSelectedFilters],
82	      },
83	    } = renderHook(() =>
84	      useUrlFilters({
85	        fields: [{ label: NAME, resourceFieldId: NAME }],
86	      }),
87	    );
88	    act(() => {
89	      setSelectedFilters({ [NAME]: update });
90	    });
91	    // eslint-disable-next-line @typescript-eslint/unbound-method
92	    expect(window.history.pushState).toBeCalledWith({}, '', pushedState);
93	  });
94	});

